INSERT INTO landmarks (name, name_bg, description, description_bg, category, lat, lng, image_url, is_active) VALUES
('Dzhumaya Mosque', 'Джумая джамия', 'The oldest Ottoman mosque in the Balkans, built in 1363–1364 during the reign of Sultan Murad I. Its impressive prayer hall is covered by nine domes and features exquisite 14th-century stonework.', 'Най-старата османска джамия на Балканите, построена през 1363–1364 г. по време на управлението на султан Мурад I.', 'historic', 42.14417, 24.74917, 'https://images.unsplash.com/photo-1577082349863-5d9c3a322f5c?w=800&h=600&fit=crop', true),
('Ancient Theatre of Philippopolis', 'Античен театър на Филипопол', 'A 2nd-century Roman theatre carved into the southern slope of the Old Town, seating up to 7,000 spectators. Restored in the 1980s.', 'Римски театър от II век, издълбан в южния склон на Стария град, с капацитет до 7 000 зрители.', 'historic', 42.14194, 24.74917, 'https://images.unsplash.com/photo-1580509042598-1c01f5cfc5a7?w=800&h=600&fit=crop', true),
('Kapana Creative District', 'Капана', 'The "trap" district — a maze of cobblestone streets filled with artisan workshops, galleries, craft breweries, and street art.', 'Кварталът "капан" — лабиринт от калдъръмени улички, изпълнени с арт работилници, галерии, занаятчийски пивоварни и улично изкуство.', 'culture', 42.14528, 24.74750, 'https://images.unsplash.com/photo-1517451336627-3d3f4f8c5b1a?w=800&h=600&fit=crop', true),
('Old Town (Staria Grad)', 'Стария град', 'The historic Old Town perched on the Three Hills, featuring preserved Bulgarian Revival houses with distinctive bay windows and cobblestone lanes.', 'Историческият Стар град, разположен на Трите хълма, с къщи от Възраждането с еркери и калдаръмени улички.', 'culture', 42.14361, 24.75139, 'https://images.unsplash.com/photo-1589371860080-e8d4c9b1f4b2?w=800&h=600&fit=crop', true),
('Plovdiv Regional Historical Museum', 'Регионален исторически музей – Пловдив', 'Housed in a magnificent 19th-century building, the museum displays over 600,000 artifacts tracing Plovdiv''s history.', 'Разположен в великолепна сграда от XIX век, музеят представя над 600 000 артефакта.', 'culture', 42.14583, 24.75028, 'https://images.unsplash.com/photo-1581873378391-5c5b5f2b7e3d?w=800&h=600&fit=crop', true),
('Tsar Simeon Garden', 'Цар Симеонова градина', 'The city''s central park, designed in the 19th century, featuring ornate fountains, a summer theatre, and the iconic Singing Fountains.', 'Централният градски парк, проектиран през XIX век, с фонтани, летен театър и емблематичните Пеещи фонтани.', 'nature', 42.14694, 24.74833, 'https://images.unsplash.com/photo-1585329759158-9c7b0e5f2a4d?w=800&h=600&fit=crop', true),
('Rowing Canal (Grebna Baza)', 'Гребна база', 'A 2.2 km man-made rowing canal surrounded by green parks, jogging and cycling paths. A popular spot for walking and sunset views.', 'Изкуствен гребен канал с дължина 2.2 км, заобиколен от паркове, алеи за бягане и колоездене.', 'nature', 42.13083, 24.72528, 'https://images.unsplash.com/photo-1576481314960-9d6e8e2b0c4f?w=800&h=600&fit=crop', true),
('Plovdiv Zoo', 'Пловдивски зоопарк', 'The oldest zoo in Bulgaria, founded in 1959, home to over 200 animals including lions, bears, monkeys, and exotic birds.', 'Най-старият зоопарк в България, основан през 1959 г., с над 200 животни.', 'nature', 42.13417, 24.72694, 'https://images.unsplash.com/photo-1580473645028-6b9f1e9d3a8c?w=800&h=600&fit=crop', true),
('Ethnographic Museum Plovdiv', 'Етнографски музей – Пловдив', 'Housed in the stunning Kuyumdzhioglu House (1847), this museum showcases Bulgarian traditional costumes, crafts, and household items.', 'Разположен в къщата на Куюмджиоглу (1847), музеят представя български народни носии, занаяти и предмети от бита.', 'culture', 42.14472, 24.75278, 'https://images.unsplash.com/photo-1576481314960-9d6e8e2b0c4f?w=800&h=600&fit=crop', true),
('Nebet Tepe Hill', 'Небет тепе', 'One of the Three Hills and the acropolis of ancient Philippopolis, with Thracian fortification walls dating to the 5th century BC.', 'Един от Трите хълма и акрополът на древния Филипопол с тракийски крепостни стени от V век пр.н.е.', 'historic', 42.14750, 24.75361, 'https://images.unsplash.com/photo-1580509042598-1c01f5cfc5a7?w=800&h=600&fit=crop', true),
('Sahat Tepe Hill', 'Сахат тепе', 'Named after the 19th-century clock tower at its summit, this hill offers wooded paths, benches, and sunset viewpoints.', 'Наречен на часовниковата кула от XIX век на върха, този хълм предлага гористи пътеки и гледки към залеза.', 'nature', 42.14639, 24.75528, 'https://images.unsplash.com/photo-1585329759158-9c7b0e5f2a4d?w=800&h=600&fit=crop', true),
('Roman Stadium of Philippopolis', 'Римски стадион на Филипопол', 'A 2nd-century Roman stadium with a capacity of 30,000 spectators, discovered beneath the main pedestrian street.', 'Римски стадион от II век с капацитет 30 000 зрители, открит под главната пешеходна улица.', 'historic', 42.14583, 24.74833, 'https://images.unsplash.com/photo-1580509042598-1c01f5cfc5a7?w=800&h=600&fit=crop', true),
('Maritsa Riverside Walk', 'Крайбрежна алея на Марица', 'A scenic promenade along the banks of the Maritsa River, lined with willow trees, benches, and cycle paths.', 'Живописна алея по бреговете на река Марица, заобиколена от върби, пейки и велоалеи.', 'nature', 42.14056, 24.74639, 'https://images.unsplash.com/photo-1576481314960-9d6e8e2b0c4f?w=800&h=600&fit=crop', true),
('Bunardzhika Hill (Singing Fountains)', 'Бунарджика (Пеещи фонтани)', 'The greenest of the Three Hills, home to the Alyosha Monument and the spectacular Singing Fountains summer show.', 'Най-зеленият от Трите хълма, дом на паметника на Альоша и Пеещите фонтани.', 'nature', 42.15083, 24.74528, 'https://images.unsplash.com/photo-1585329759158-9c7b0e5f2a4d?w=800&h=600&fit=crop', true),
('Alyosha Monument', 'Паметник на Альоша', 'An iconic 11-metre Soviet soldier statue atop Bunardzhika Hill, erected in 1954, offering a commanding view of Plovdiv.', 'Емблематична 11-метрова статуя на съветски войник на хълма Бунарджика, издигната през 1954 г.', 'historic', 42.15472, 24.75500, 'https://images.unsplash.com/photo-1580509042598-1c01f5cfc5a7?w=800&h=600&fit=crop', true),
('Hristo Danov Monument', 'Паметник на Христо Г. Данов', 'A bronze statue of Hristo G. Danov, Bulgaria''s pioneering publisher, standing in the central pedestrian zone.', 'Бронзова статуя на Христо Г. Данов, българският книгоиздател пионер, в централната пешеходна зона.', 'historic', 42.14583, 24.74917, 'https://images.unsplash.com/photo-1564013799919-ab600027ffc6?w=800&h=600&fit=crop', true),
('Plovdiv Central Railway Station', 'Централна гара Пловдив', 'Built in 1872, the station is one of the oldest railway buildings in Bulgaria with its neo-classical facade.', 'Построена през 1872 г., гарата е една от най-старите железопътни сгради в България с неокласическа фасада.', 'historic', 42.13694, 24.74889, 'https://images.unsplash.com/photo-1517451336627-3d3f4f8c5b1a?w=800&h=600&fit=crop', true),
('Plovdiv Art Gallery', 'Пловдивска художествена галерия', 'The city''s main art museum, housing over 5,000 works of Bulgarian fine art from the National Revival to contemporary pieces.', 'Главният художествен музей на града с над 5 000 творби на българското изобразително изкуство.', 'culture', 42.14583, 24.75111, 'https://images.unsplash.com/photo-1581873378391-5c5b5f2b7e3d?w=800&h=600&fit=crop', true),
('Lamartin House', 'Къща на Ламартин', 'The house where French poet Alphonse de Lamartine stayed during his 1833 travels. Now a museum dedicated to his life.', 'Къщата, в която френският поет Алфонс дьо Ламартин отсяда по време на пътуванията си през 1833 г.', 'historic', 42.14639, 24.75194, 'https://images.unsplash.com/photo-1564013799919-ab600027ffc6?w=800&h=600&fit=crop', true),
('Philippopolis Art Gallery', 'Художествена галерия Филипопол', 'A contemporary art space in a restored 19th-century building near the Ancient Theatre. Features rotating exhibitions.', 'Съвременно арт пространство в реновирана сграда от XIX век близо до Античния театър.', 'culture', 42.14444, 24.75083, 'https://images.unsplash.com/photo-1581873378391-5c5b5f2b7e3d?w=800&h=600&fit=crop', true),
('Danov House', 'Къща на Данов', 'The birthplace of Hristo G. Danov, founder of modern Bulgarian publishing. Now a museum of printing and book publishing.', 'Родното място на Христо Г. Данов, основател на съвременното българско книгоиздаване.', 'culture', 42.14500, 24.75167, 'https://images.unsplash.com/photo-1564013799919-ab600027ffc6?w=800&h=600&fit=crop', true),
('Balabanov House', 'Къща на Балабанов', 'A meticulously restored Bulgarian National Revival house (c. 1850) with a spacious courtyard and ornate wooden ceilings.', 'Внимателно реставрирана къща от Българското възраждане (ок. 1850 г.) с просторен двор и дървени тавани.', 'culture', 42.14444, 24.75222, 'https://images.unsplash.com/photo-1564013799919-ab600027ffc6?w=800&h=600&fit=crop', true),
('Church of Saints Konstantin and Elena', 'Църква "Св. св. Константин и Елена"', 'An Eastern Orthodox church built in 1832 atop an earlier medieval Christian site. Features a magnificent iconostasis.', 'Източноправославна църква, построена през 1832 г. върху по-ранен средновековен християнски обект.', 'historic', 42.14528, 24.75306, 'https://images.unsplash.com/photo-1577082349863-5d9c3a322f5c?w=800&h=600&fit=crop', true),
('Church of the Virgin Mary', 'Църква "Света Богородица"', 'A Bulgarian Orthodox church built in 1844, featuring a carved wooden iconostasis and impressive murals.', 'Българска православна църква, построена през 1844 г., с резбован иконостас и впечатляващи стенописи.', 'historic', 42.14611, 24.75361, 'https://images.unsplash.com/photo-1577082349863-5d9c3a322f5c?w=800&h=600&fit=crop', true),
('Hebros Hotel & Roman Wall', 'Хотел Хеброс и Римска стена', 'A section of the ancient Roman fortification wall of Philippopolis, integrated into the modern Hebros Hotel building.', 'Част от древната римска крепостна стена на Филипопол, интегрирана в модерната сграда на хотел Хеброс.', 'historic', 42.14528, 24.75194, 'https://images.unsplash.com/photo-1580509042598-1c01f5cfc5a7?w=800&h=600&fit=crop', true),
('Plovdiv Fair', 'Панаир Пловдив', 'One of the largest exhibition centres in Southeast Europe, hosting international trade fairs since 1892.', 'Един от най-големите изложбени центрове в Югоизточна Европа, домакин на международни панаири от 1892 г.', 'culture', 42.13361, 24.73083, 'https://images.unsplash.com/photo-1564013799919-ab600027ffc6?w=800&h=600&fit=crop', true)
